async (params, browser) => {
  // Search local news on Google News
  await browser.open('https://news.google.com/search')

  // Wait for local news results
  await browser.waitForSelector('article, c-wiz article, [data-n-tid]', 15000)

  // Let results render
  await browser.wait(2500)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract local news articles
  const local_data = await browser.evaluate(`const articles = []; const items = document.querySelectorAll('article, c-wiz article'); for (let i = 0; i < Math.min(items.length, 15); i++) { const item = items[i]; const linkEl = item.querySelector('a[href*="./articles/"], a[href*="./read/"], a[href^="https"]'); const titleEl = linkEl ? linkEl.querySelector('h3, h4, .JtKRv') || linkEl : null; const sourceEl = item.querySelector('.vr1PYe, [data-n-tid], .wsn2rd, div > div > a[data-n-tid]'); const timeEl = item.querySelector('time, .hvbAAd, datetime'); const snippetEl = item.querySelector('.GI74Re, .xBbh9, .Y8wuc'); let url = ''; if (linkEl) { const href = linkEl.getAttribute('href') || ''; if (href.startsWith('./')) { url = 'https://news.google.com/' + href.slice(2); } else if (href.startsWith('http')) { url = href; } else { url = 'https://news.google.com/' + href; } } articles.push({ title: titleEl ? titleEl.textContent.trim() : '', source: sourceEl ? sourceEl.textContent.trim() : '', time: timeEl ? (timeEl.getAttribute('datetime') || timeEl.textContent.trim()) : '', snippet: snippetEl ? snippetEl.textContent.trim().slice(0, 300) : '', url: url }); } const urlParams = new URLSearchParams(window.location.search); const loc = urlParams.get('q') || ''; return { location: loc.replace(/ local news$/i, ''), source: 'Google News - Local', article_count: articles.length, articles: articles }`)

  return local_data
}
